import{_ as a,o as e,c as s,ae as n}from"./chunks/framework.Co1PSFSm.js";const u=JSON.parse('{"title":"AstrBot Architecture Analysis","description":"","frontmatter":{},"headers":[],"relativePath":"architecture.md","filePath":"architecture.md"}'),o={name:"architecture.md"};function r(i,t,l,d,p,c){return e(),s("div",null,[...t[0]||(t[0]=[n(`<h1 id="astrbot-architecture-analysis" tabindex="-1">AstrBot Architecture Analysis <a class="header-anchor" href="#astrbot-architecture-analysis" aria-label="Permalink to &quot;AstrBot Architecture Analysis&quot;">​</a></h1><h2 id="_1-system-overview" tabindex="-1">1. System Overview <a class="header-anchor" href="#_1-system-overview" aria-label="Permalink to &quot;1. System Overview&quot;">​</a></h2><p>AstrBot is a modular AI Agent framework supporting multiple chat platforms, LLM providers, and extensible plugin system.</p><h2 id="_2-core-modules" tabindex="-1">2. Core Modules <a class="header-anchor" href="#_2-core-modules" aria-label="Permalink to &quot;2. Core Modules&quot;">​</a></h2><h3 id="_2-1-astrbot-core-core-engine" tabindex="-1">2.1 astrbot/core - Core Engine <a class="header-anchor" href="#_2-1-astrbot-core-core-engine" aria-label="Permalink to &quot;2.1 astrbot/core - Core Engine&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Module</th><th>Path</th><th>Description</th></tr></thead><tbody><tr><td><strong>agent</strong></td><td><code>core/agent/</code></td><td>Agent execution engine, context management, tool execution</td></tr><tr><td><strong>pipeline</strong></td><td><code>core/pipeline/</code></td><td>Message processing pipeline (preprocess → process → respond)</td></tr><tr><td><strong>provider</strong></td><td><code>core/provider/</code></td><td>LLM provider abstraction layer</td></tr><tr><td><strong>platform</strong></td><td><code>core/platform/</code></td><td>Multi-platform adapter system</td></tr><tr><td><strong>skills</strong></td><td><code>core/skills/</code></td><td>Skill management system</td></tr><tr><td><strong>knowledge_base</strong></td><td><code>core/knowledge_base/</code></td><td>RAG knowledge base with FAISS</td></tr><tr><td><strong>computer</strong></td><td><code>core/computer/</code></td><td>Computer use tools (shell, python, browser)</td></tr><tr><td><strong>tools</strong></td><td><code>core/tools/</code></td><td>Tool registry and implementations</td></tr><tr><td><strong>db</strong></td><td><code>core/db/</code></td><td>SQLite + FAISS vector database</td></tr><tr><td><strong>cron</strong></td><td><code>core/cron/</code></td><td>Scheduled task system</td></tr><tr><td><strong>config</strong></td><td><code>core/config/</code></td><td>Configuration management</td></tr></tbody></table><h3 id="_2-2-astrbot-builtin-stars-built-in-extensions" tabindex="-1">2.2 astrbot/builtin_stars - Built-in Extensions <a class="header-anchor" href="#_2-2-astrbot-builtin-stars-built-in-extensions" aria-label="Permalink to &quot;2.2 astrbot/builtin_stars - Built-in Extensions&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Module</th><th>Path</th><th>Description</th></tr></thead><tbody><tr><td><strong>astrbot</strong></td><td><code>builtin_stars/astrbot/</code></td><td>Core bot functionality (long-term memory)</td></tr><tr><td><strong>builtin_commands</strong></td><td><code>builtin_stars/builtin_commands/</code></td><td>Admin, help, provider, conversation commands</td></tr></tbody></table><h3 id="_2-3-astrbot-api-public-api" tabindex="-1">2.3 astrbot/api - Public API <a class="header-anchor" href="#_2-3-astrbot-api-public-api" aria-label="Permalink to &quot;2.3 astrbot/api - Public API&quot;">​</a></h3><p>FastAPI-based API server exposing endpoints for:</p><ul><li>Chat operations</li><li>Plugin management</li><li>Knowledge base</li><li>Session management</li><li>Platform configuration</li></ul><h3 id="_2-4-dashboard-webui" tabindex="-1">2.4 dashboard - WebUI <a class="header-anchor" href="#_2-4-dashboard-webui" aria-label="Permalink to &quot;2.4 dashboard - WebUI&quot;">​</a></h3><p>React + Vuetify + Vue 3 management dashboard.</p><h2 id="_3-key-design-patterns" tabindex="-1">3. Key Design Patterns <a class="header-anchor" href="#_3-key-design-patterns" aria-label="Permalink to &quot;3. Key Design Patterns&quot;">​</a></h2><h3 id="_3-1-provider-pattern" tabindex="-1">3.1 Provider Pattern <a class="header-anchor" href="#_3-1-provider-pattern" aria-label="Permalink to &quot;3.1 Provider Pattern&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Provider (abstract)</span></span>
<span class="line"><span>├── OpenAISource</span></span>
<span class="line"><span>├── AnthropicSource</span></span>
<span class="line"><span>├── DashscopeSource</span></span>
<span class="line"><span>├── GeminiSource</span></span>
<span class="line"><span>└── ... (20+ providers)</span></span></code></pre></div><h3 id="_3-2-platform-adapter-pattern" tabindex="-1">3.2 Platform Adapter Pattern <a class="header-anchor" href="#_3-2-platform-adapter-pattern" aria-label="Permalink to &quot;3.2 Platform Adapter Pattern&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Platform (abstract)</span></span>
<span class="line"><span>├── TelegramAdapter</span></span>
<span class="line"><span>├── DiscordAdapter</span></span>
<span class="line"><span>├── QQAdapter</span></span>
<span class="line"><span>├── WechatAdapter</span></span>
<span class="line"><span>├── LarkAdapter</span></span>
<span class="line"><span>└── ... (15+ platforms)</span></span></code></pre></div><h3 id="_3-3-pipeline-pattern" tabindex="-1">3.3 Pipeline Pattern <a class="header-anchor" href="#_3-3-pipeline-pattern" aria-label="Permalink to &quot;3.3 Pipeline Pattern&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Message → Preprocess → Process (Agent) → Respond → Decorate → Output</span></span></code></pre></div><h3 id="_3-4-star-plugin-pattern" tabindex="-1">3.4 Star/Plugin Pattern <a class="header-anchor" href="#_3-4-star-plugin-pattern" aria-label="Permalink to &quot;3.4 Star/Plugin Pattern&quot;">​</a></h3><p>Extension system with:</p><ul><li><code>metadata.yaml</code> - Plugin definition</li><li><code>i18n/</code> - Internationalization</li><li><code>main.py</code> - Entry point</li><li><code>.astrbot-plugin/</code> - Marker directory</li></ul><h2 id="_4-data-flow" tabindex="-1">4. Data Flow <a class="header-anchor" href="#_4-data-flow" aria-label="Permalink to &quot;4. Data Flow&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User Message</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>Platform Adapter (convert to AStrBotMessage)</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>Pipeline: Preprocess → Content Safety → Rate Limit → Wake Check</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>Agent (LLM + Tools)</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>Pipeline: Respond → Result Decorate</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>Platform Adapter (convert to platform-specific format)</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>User Response</span></span></code></pre></div><h2 id="_5-extension-points" tabindex="-1">5. Extension Points <a class="header-anchor" href="#_5-extension-points" aria-label="Permalink to &quot;5. Extension Points&quot;">​</a></h2><h3 id="_5-1-stars-plugins" tabindex="-1">5.1 Stars (Plugins) <a class="header-anchor" href="#_5-1-stars-plugins" aria-label="Permalink to &quot;5.1 Stars (Plugins)&quot;">​</a></h3><ul><li>Location: <code>~/.astrbot/stars/</code></li><li>Interface: <code>astrbot.api.star.StarBase</code></li><li>Capabilities: Commands, web pages, scheduled tasks</li></ul><h3 id="_5-2-tools" tabindex="-1">5.2 Tools <a class="header-anchor" href="#_5-2-tools" aria-label="Permalink to &quot;5.2 Tools&quot;">​</a></h3><ul><li>Built-in: web_search, file_system, shell, python, browser</li><li>Custom: via MCP or plugin-provided</li></ul><h3 id="_5-3-agent-runners" tabindex="-1">5.3 Agent Runners <a class="header-anchor" href="#_5-3-agent-runners" aria-label="Permalink to &quot;5.3 Agent Runners&quot;">​</a></h3><ul><li>ToolLoopAgentRunner (default)</li><li>CozeAgentRunner</li><li>DeerFlowAgentRunner</li><li>DifyAgentRunner</li></ul><h2 id="_6-technology-stack" tabindex="-1">6. Technology Stack <a class="header-anchor" href="#_6-technology-stack" aria-label="Permalink to &quot;6. Technology Stack&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Layer</th><th>Technology</th></tr></thead><tbody><tr><td>Core</td><td>Python 3.10+, asyncio</td></tr><tr><td>API</td><td>FastAPI, uvicorn</td></tr><tr><td>Database</td><td>SQLite + FAISS</td></tr><tr><td>Frontend</td><td>React 3, Vuetify 3, TypeScript</td></tr><tr><td>Package</td><td>uv (Python), pnpm (Node)</td></tr><tr><td>Container</td><td>Docker, Docker Compose</td></tr><tr><td>Orchestration</td><td>Kubernetes</td></tr></tbody></table><h2 id="_7-directory-structure" tabindex="-1">7. Directory Structure <a class="header-anchor" href="#_7-directory-structure" aria-label="Permalink to &quot;7. Directory Structure&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>astrbot/</span></span>
<span class="line"><span>├── api/              # FastAPI endpoints</span></span>
<span class="line"><span>├── builtin_stars/    # Built-in extensions</span></span>
<span class="line"><span>├── cli/              # CLI commands</span></span>
<span class="line"><span>├── core/             # Core engine</span></span>
<span class="line"><span>│   ├── agent/        # Agent logic</span></span>
<span class="line"><span>│   ├── computer/      # Computer use</span></span>
<span class="line"><span>│   ├── config/       # Configuration</span></span>
<span class="line"><span>│   ├── knowledge_base/ # RAG</span></span>
<span class="line"><span>│   ├── platform/     # Platform adapters</span></span>
<span class="line"><span>│   ├── pipeline/     # Processing pipeline</span></span>
<span class="line"><span>│   ├── provider/     # LLM providers</span></span>
<span class="line"><span>│   ├── skills/       # Skills system</span></span>
<span class="line"><span>│   └── tools/        # Tool registry</span></span>
<span class="line"><span>├── dashboard/        # WebUI (Vue)</span></span>
<span class="line"><span>├── docs/             # Documentation</span></span>
<span class="line"><span>├── tests/            # Test suite</span></span>
<span class="line"><span>└── main.py           # Entry point</span></span></code></pre></div><h2 id="_8-configuration" tabindex="-1">8. Configuration <a class="header-anchor" href="#_8-configuration" aria-label="Permalink to &quot;8. Configuration&quot;">​</a></h2><ul><li>Default config: <code>astrbot/core/config/default.py</code></li><li>User config: <code>~/.astrbot/config.yaml</code></li><li>Platform-specific configs in <code>astrbot/core/platform/sources/</code></li></ul><h2 id="_9-key-files" tabindex="-1">9. Key Files <a class="header-anchor" href="#_9-key-files" aria-label="Permalink to &quot;9. Key Files&quot;">​</a></h2><table tabindex="0"><thead><tr><th>File</th><th>Purpose</th></tr></thead><tbody><tr><td><code>main.py</code></td><td>Application entry point</td></tr><tr><td><code>runtime_bootstrap.py</code></td><td>Runtime initialization</td></tr><tr><td><code>pyproject.toml</code></td><td>Python dependencies</td></tr><tr><td><code>AGENTS.md</code></td><td>Developer guide</td></tr><tr><td><code>.pre-commit-config.yaml</code></td><td>Pre-commit hooks</td></tr></tbody></table>`,40)])])}const b=a(o,[["render",r]]);export{u as __pageData,b as default};
